47	func getAuthenticationFilterResolverForNamespace(
48		authenticationFilters map[types.NamespacedName]*AuthenticationFilter,
49		namespace string,
50	) resolveExtRefFilter {
51		return func(ref v1.LocalObjectReference) *ExtensionRefFilter {
52			if len(authenticationFilters) == 0 {
53				return nil
54			}
55	
56			if ref.Group != ngfAPI.GroupName || ref.Kind != kinds.AuthenticationFilter {
57				return nil
58			}
59	
60			af := authenticationFilters[types.NamespacedName{Namespace: namespace, Name: string(ref.Name)}]
61			if af == nil {
62				return nil
63			}
64	
65			af.Referenced = true
66	
67			return &ExtensionRefFilter{AuthenticationFilter: af, Valid: af.Valid}
68		}
69	}
