71	func processAuthenticationFilters(
72		authenticationFilters map[types.NamespacedName]*ngfAPI.AuthenticationFilter,
73		resourceResolver resolver.Resolver,
74		authValidator validation.AuthFieldsValidator,
75		genericValidator validation.GenericValidator,
76		isPlus bool,
77	) map[types.NamespacedName]*AuthenticationFilter {
78		if len(authenticationFilters) == 0 {
79			return nil
80		}
81	
82		processed := make(map[types.NamespacedName]*AuthenticationFilter, len(authenticationFilters))
83	
84		for nsname, af := range authenticationFilters {
85			conds, valid := validateAuthenticationFilter(af, nsname, resourceResolver, authValidator, genericValidator, isPlus)
86			processed[nsname] = &AuthenticationFilter{
87				Source:     af,
88				Conditions: conds,
89				Valid:      valid,
90			}
91		}
92	
93		return processed
94	}
