96	func validateAuthenticationFilter(
97		af *ngfAPI.AuthenticationFilter,
98		nsname types.NamespacedName,
99		resourceResolver resolver.Resolver,
100		authValidator validation.AuthFieldsValidator,
101		genericValidator validation.GenericValidator,
102		isPlus bool,
103	) ([]conditions.Condition, bool) {
104		var conds []conditions.Condition
105		valid := true
106	
107		switch af.Spec.Type {
108		case ngfAPI.AuthTypeBasic:
109			authBasicSecretNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: af.Spec.Basic.SecretRef.Name}
110			conds, valid = resolveAuthenticationFilterSecret(
111				authBasicSecretNsName,
112				resourceResolver,
113				field.NewPath("spec.basic.secretRef"),
114			)
115		case ngfAPI.AuthTypeJWT:
116			if !isPlus {
117				cond := conditions.NewAuthenticationFilterInvalid("JWT Authentication requires NGINX Plus.")
118				return []conditions.Condition{cond}, false
119			}
120			if af.Spec.JWT.Source == ngfAPI.JWTKeySourceFile {
121				authJWTSecretNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: af.Spec.JWT.File.SecretRef.Name}
122				conds, valid = resolveAuthenticationFilterSecret(
123					authJWTSecretNsName,
124					resourceResolver,
125					field.NewPath("spec.jwt.file.secretRef"),
126				)
127			} else if af.Spec.JWT.Source == ngfAPI.JWTKeySourceRemote && af.Spec.JWT.Remote != nil {
128				conds, valid = validateRemoteJWT(af, nsname, resourceResolver)
129			}
130			if af.Spec.JWT.Authorization != nil {
131				if authZErrs := validateJWTAuthorization(af.Spec.JWT.Authorization, authValidator); len(authZErrs) > 0 {
132					conds = append(conds, conditions.NewAuthenticationFilterInvalid(authZErrs.ToAggregate().Error()))
133					valid = false
134				}
135			}
136		case ngfAPI.AuthTypeOIDC:
137			if !isPlus {
138				cond := conditions.NewAuthenticationFilterInvalid("OIDC Authentication requires NGINX Plus.")
139				return []conditions.Condition{cond}, false
140			}
141			conds, valid = validateOIDC(af.Spec.OIDC, nsname, resourceResolver, authValidator, genericValidator)
142		default:
143			err := field.Invalid(
144				field.NewPath("spec.type"),
145				af.Spec.Type,
146				"unsupported authentication type",
147			)
148			conds = append(conds, conditions.NewAuthenticationFilterInvalid(err.Error()))
149			valid = false
150		}
151	
152		return conds, valid
153	}
