159	) ([]conditions.Condition, bool) {
160		var allErrs field.ErrorList
161		for _, caCertRef := range af.Spec.JWT.Remote.CACertificateRefs {
162			caCertNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: caCertRef.Name}
163			if err := resourceResolver.Resolve(resolver.ResourceTypeSecret, caCertNsName,
164				resolver.WithExpectedSecretKey(secrets.CAKey)); err != nil {
165				allErrs = append(allErrs, field.Invalid(
166					field.NewPath("spec.jwt.remote.caCertificateRefs"),
167					caCertRef.Name,
168					err.Error(),
169				))
170			}
171		}
172	
173		if allErrs != nil {
174			cond := conditions.NewAuthenticationFilterInvalid(allErrs.ToAggregate().Error())
175			return []conditions.Condition{cond}, false
176		}
177	
178		return nil, true
179	}
