181	func validateJWTAuthorization(
182		authz *ngfAPI.Authorization,
183		authValidator validation.AuthFieldsValidator,
184	) field.ErrorList {
185		var allErrs field.ErrorList
186	
187		// Track sanitized claim names across all rules to detect collisions.
188		// Key: sanitized name, Value: original claim name that first produced it.
189		globalSanitizedNames := make(map[string]string)
190	
191		for ruleIdx, rule := range authz.Rules {
192			rulePath := field.NewPath("spec.jwt.authorization.rules").Index(ruleIdx)
193	
194			for claimIdx, claim := range rule.Claims {
195				claimPath := rulePath.Child("claims").Index(claimIdx)
196	
197				if err := authValidator.ValidateAuthZClaimName(claim.Name); err != nil {
198					allErrs = append(allErrs, field.Invalid(
199						claimPath.Child("name"),
200						claim.Name,
201						err.Error(),
202					))
203				}
204	
205				// Check for sanitized name collisions across all rules.
206				// NGINX variable names only allow [a-zA-Z0-9_], so characters like -, ., /
207				// are replaced with underscores. This means distinct claim names like
208				// "realm_access/roles" and "realm_access_roles" would map to the same
209				// NGINX variable, causing silent incorrect authorization decisions.
210				sanitized := sanitizeClaimNameForVariable(claim.Name)
211				if originalName, exists := globalSanitizedNames[sanitized]; exists {
212					if originalName != claim.Name {
213						allErrs = append(allErrs, field.Invalid(
214							claimPath.Child("name"),
215							claim.Name,
216							fmt.Sprintf(
217								"claim name produces the same NGINX variable name as %q after sanitization "+
218									"(both become %q); use distinct claim names that don't collide",
219								originalName, sanitized,
220							),
221						))
222					}
223				} else {
224					globalSanitizedNames[sanitized] = claim.Name
225				}
226	
227				for valueIdx, value := range claim.Values {
228					if err := authValidator.ValidateAuthZClaimValue(value); err != nil {
229						allErrs = append(allErrs, field.Invalid(
230							claimPath.Child("values").Index(valueIdx),
231							value,
232							err.Error(),
233						))
234					}
235				}
236	
237				if claim.ProxySetHeader != nil {
238					if err := authValidator.ValidateAuthZProxySetHeader(*claim.ProxySetHeader); err != nil {
239						allErrs = append(allErrs, field.Invalid(
240							claimPath.Child("proxySetHeader"),
241							*claim.ProxySetHeader,
242							err.Error(),
243						))
244					}
245				}
246			}
247		}
248	
249		return allErrs
250	}
251	
252	// sanitizeClaimNameForVariable applies the same sanitization as the dataplane's
253	// sanitizeVariablePrefix: it replaces characters that are invalid in NGINX variable
254	// names (-, ., /) with underscores. This is used during validation to detect claim
255	// names that would collide when converted to NGINX variables.
256	func sanitizeClaimNameForVariable(name string) string {
257		return strings.NewReplacer("-", "_", ".", "_", "/", "_").Replace(name)
258	}
