263		path *field.Path,
264	) ([]conditions.Condition, bool) {
265		var allErrs field.ErrorList
266	
267		if err := resourceResolver.Resolve(
268			resolver.ResourceTypeSecret,
269			authSecretNsName,
270			resolver.WithExpectedSecretKey(secrets.AuthKey),
271		); err != nil {
272			allErrs = append(allErrs, field.Invalid(
273				path,
274				fmt.Sprintf("secret %s/%s is invalid", authSecretNsName.Namespace, authSecretNsName.Name),
275				err.Error(),
276			))
277		}
278	
279		if allErrs != nil {
280			cond := conditions.NewAuthenticationFilterInvalid(allErrs.ToAggregate().Error())
281			return []conditions.Condition{cond}, false
282		}
283	
284		// FIXME(s.odonovan): Remove this secret type 3 releases after 2.5.0.
285		// Issue https://github.com/nginx/nginx-gateway-fabric/issues/4870 will remove this secret type.
286		return resolveHtPasswdSecret(authSecretNsName, resourceResolver)
