289	func resolveHtPasswdSecret(
290		authSecretNsName types.NamespacedName,
291		resourceResolver resolver.Resolver,
292	) ([]conditions.Condition, bool) {
293		secretsMap := resourceResolver.GetSecrets()[authSecretNsName]
294		if secretsMap == nil || secretsMap.Source == nil {
295			cond := conditions.NewAuthenticationFilterInvalid(
296				fmt.Sprintf("failed to resolve resource. Secret %s/%s is invalid or missing.",
297					authSecretNsName.Namespace,
298					authSecretNsName.Name),
299			)
300			return []conditions.Condition{cond}, false
301		}
302	
303		if secretsMap.Source.Type == corev1.SecretType(secrets.SecretTypeHtpasswd) {
304			msg := fmt.Sprintf(
305				"The AuthenticationFilter is accepted,"+
306					" but the referenced Secret %s/%s of type %q is now deprecated."+
307					" This secret type will be removed in a future release."+
308					" Please use type %q instead.",
309				authSecretNsName.Namespace,
310				authSecretNsName.Name,
311				secretsMap.Source.Type,
312				corev1.SecretTypeOpaque,
313			)
314			cond := conditions.NewAuthenticationFilterAcceptedWithMessage(msg)
315			return []conditions.Condition{cond}, true
316		}
317		return nil, true
318	}
