320	func validateOIDC(
321		oidcSpec *ngfAPI.OIDCAuth,
322		nsname types.NamespacedName,
323		resourceResolver resolver.Resolver,
324		authValidator validation.AuthFieldsValidator,
325		genericValidator validation.GenericValidator,
326	) ([]conditions.Condition, bool) {
327		var allErrs field.ErrorList
328	
329		allErrs = append(allErrs, validateOIDCFields(oidcSpec, authValidator, genericValidator)...)
330		allErrs = append(allErrs, validateOIDCSecretRefs(oidcSpec, nsname, resourceResolver)...)
331		allErrs = append(allErrs, validateOIDCLogoutURIs(oidcSpec, authValidator)...)
332	
333		if allErrs != nil {
334			return []conditions.Condition{conditions.NewAuthenticationFilterInvalid(allErrs.ToAggregate().Error())}, false
335		}
