340	func validateOIDCFields(
341		oidcSpec *ngfAPI.OIDCAuth,
342		authValidator validation.AuthFieldsValidator,
343		genericValidator validation.GenericValidator,
344	) field.ErrorList {
345		var allErrs field.ErrorList
346	
347		if err := authValidator.ValidateOIDCIssuer(oidcSpec.Issuer); err != nil {
348			allErrs = append(allErrs, field.Invalid(
349				field.NewPath("spec.oidc.issuer"),
350				oidcSpec.Issuer,
351				err.Error(),
352			))
353		}
354		if oidcSpec.ConfigURL != nil {
355			if err := authValidator.ValidateOIDCConfigURL(*oidcSpec.ConfigURL); err != nil {
356				allErrs = append(allErrs, field.Invalid(
357					field.NewPath("spec.oidc.configURL"),
358					*oidcSpec.ConfigURL,
359					err.Error(),
360				))
361			}
362		}
363		if oidcSpec.RedirectURI != nil {
364			if err := authValidator.ValidateOIDCRedirectURI(*oidcSpec.RedirectURI); err != nil {
365				allErrs = append(allErrs, field.Invalid(
366					field.NewPath("spec.oidc.redirectURI"),
367					*oidcSpec.RedirectURI,
368					err.Error(),
369				))
370			}
371		}
372		if oidcSpec.Session != nil && oidcSpec.Session.Timeout != nil {
373			if err := genericValidator.ValidateNginxDuration(string(*oidcSpec.Session.Timeout)); err != nil {
374				allErrs = append(allErrs, field.Invalid(
375					field.NewPath("spec.oidc.session.timeout"),
376					*oidcSpec.Session.Timeout,
377					err.Error(),
378				))
379			}
380		}
381	
382		extraAuthArgsPath := field.NewPath("spec", "oidc", "extraAuthArgs")
383		for key, value := range oidcSpec.ExtraAuthArgs {
384			if err := authValidator.ValidateOIDCExtraAuthArg(key, value); err != nil {
385				allErrs = append(allErrs, field.Invalid(
386					extraAuthArgsPath,
387					key+"="+value,
388					err.Error(),
389				))
390			}
391		}
392	
393		return allErrs
394	}
