396	func validateOIDCSecretRefs(
397		oidcSpec *ngfAPI.OIDCAuth,
398		nsname types.NamespacedName,
399		resourceResolver resolver.Resolver,
400	) field.ErrorList {
401		var allErrs field.ErrorList
402	
403		clientSecretNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: oidcSpec.ClientSecretRef.Name}
404		if err := resourceResolver.Resolve(resolver.ResourceTypeSecret, clientSecretNsName,
405			resolver.WithExpectedSecretKey(secrets.ClientSecretKey)); err != nil {
406			allErrs = append(allErrs, field.Invalid(
407				field.NewPath("spec.oidc.clientSecretRef"),
408				oidcSpec.ClientSecretRef.Name,
409				err.Error(),
410			))
411		}
412		if len(oidcSpec.CACertificateRefs) > 1 {
413			allErrs = append(allErrs, field.Invalid(
414				field.NewPath("spec.oidc.caCertificateRefs"),
415				len(oidcSpec.CACertificateRefs),
416				"at most one CA certificate reference is supported for OIDC authentication filters",
417			))
418			return allErrs
419		}
420		for _, caCertRef := range oidcSpec.CACertificateRefs {
421			caCertNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: caCertRef.Name}
422			if err := resourceResolver.Resolve(resolver.ResourceTypeSecret, caCertNsName,
423				resolver.WithExpectedSecretKey(secrets.CAKey)); err != nil {
424				allErrs = append(allErrs, field.Invalid(
425					field.NewPath("spec.oidc.caCertificateRefs"),
426					caCertRef.Name,
427					err.Error(),
428				))
429			}
430		}
431		if oidcSpec.CRLSecretRef != nil {
432			crlNsName := types.NamespacedName{Namespace: nsname.Namespace, Name: oidcSpec.CRLSecretRef.Name}
433			if err := resourceResolver.Resolve(resolver.ResourceTypeSecret, crlNsName,
434				resolver.WithExpectedSecretKey(secrets.CRLKey)); err != nil {
435				allErrs = append(allErrs, field.Invalid(
436					field.NewPath("spec.oidc.crlSecretRef"),
437					oidcSpec.CRLSecretRef.Name,
438					err.Error(),
439				))
440			}
441		}
442	
443		return allErrs
444	}
445	
446	func validateOIDCLogoutURIs(
447		oidcSpec *ngfAPI.OIDCAuth,
448		authValidator validation.AuthFieldsValidator,
449	) field.ErrorList {
450		logout := oidcSpec.Logout
451		if logout == nil {
452			return nil
453		}
454	
455		var allErrs field.ErrorList
456	
457		if logout.URI != nil {
458			if err := authValidator.ValidateOIDCLogoutURI(*logout.URI); err != nil {
459				allErrs = append(allErrs, field.Invalid(field.NewPath("spec.oidc.logout.uri"), *logout.URI, err.Error()))
460			}
461		}
462		if logout.PostLogoutURI != nil {
463			if err := authValidator.ValidateOIDCPostLogoutURI(*logout.PostLogoutURI); err != nil {
464				allErrs = append(
465					allErrs,
466					field.Invalid(field.NewPath("spec.oidc.logout.postLogoutURI"), *logout.PostLogoutURI, err.Error()),
467				)
468			}
469		}
470		if logout.FrontChannelLogoutURI != nil {
471			if err := authValidator.ValidateOIDCFrontChannelLogoutURI(*logout.FrontChannelLogoutURI); err != nil {
472				allErrs = append(
473					allErrs,
474					field.Invalid(field.NewPath("spec.oidc.logout.frontChannelLogoutURI"), *logout.FrontChannelLogoutURI, err.Error()),
475				)
476			}
477		}
478	
479		return allErrs
480	}
481	
482	// validateOIDCFilters performs all post-binding OIDC validations in a single pass over routes and rules:
483	//   - filters attached to non-HTTPS listeners are marked invalid immediately
484	//   - the remaining valid filters are collected for URI conflict detection across shared hostnames
485	func validateOIDCFilters(routes map[RouteKey]*L7Route, gws map[types.NamespacedName]*Gateway) {
486		listenerProtocols := buildListenerProtocolMap(gws)
487		hostnameToFilters, filterRefs := collectOIDCFilterInfo(routes, listenerProtocols)
488		for hostname, filtersMap := range hostnameToFilters {
489			if len(filtersMap) >= 2 {
490				checkOIDCURIConflictsForHostname(hostname, filtersMap)
491			}
492		}
493		propagateInvalidOIDCFiltersToRouteRules(filterRefs)
494	}
495	
496	// buildListenerProtocolMap returns a map from listener key to protocol for all listeners across all gateways.
497	func buildListenerProtocolMap(gws map[types.NamespacedName]*Gateway) map[string]v1.ProtocolType {
498		protocols := make(map[string]v1.ProtocolType)
499		for _, gw := range gws {
500			for _, l := range gw.Listeners {
501				protocols[CreateParentRefListenerKeyFromListener(l)] = l.Source.Protocol
502			}
503		}
504		return protocols
505	}
506	
507	// hasNonHTTPSAttachment reports whether any of the parent refs has at least one accepted hostname
508	// on a non-HTTPS listener.
509	func hasNonHTTPSAttachment(parentRefs []ParentRef, listenerProtocols map[string]v1.ProtocolType) bool {
510		for _, ref := range parentRefs {
511			if ref.Attachment == nil {
512				continue
513			}
514			for listenerKey, hostnames := range ref.Attachment.AcceptedHostnames {
515				if len(hostnames) == 0 {
516					continue
517				}
518				protocol, ok := listenerProtocols[listenerKey]
519				if !ok {
520					continue
521				}
522				if protocol != v1.HTTPSProtocolType {
523					return true
524				}
525			}
526		}
527		return false
528	}
529	
530	// collectOIDCFilterInfo performs a single pass over all valid routes and rules.
531	// For each OIDC filter encountered:
532	//   - if its route has a non-HTTPS listener attachment and the filter is still valid, it is marked invalid
533	//   - all filters (valid or not) are registered in filterRefs for propagation
534	//   - only valid filters are registered in hostnameToFilters for URI conflict detection
535	func collectOIDCFilterInfo(
536		routes map[RouteKey]*L7Route,
537		listenerProtocols map[string]v1.ProtocolType,
538	) (
539		map[v1.Hostname]map[types.NamespacedName]*AuthenticationFilter,
540		map[*AuthenticationFilter][]oidcRuleRef,
541	) {
542		hostnameToFilters := make(map[v1.Hostname]map[types.NamespacedName]*AuthenticationFilter)
543		filterRefs := make(map[*AuthenticationFilter][]oidcRuleRef)
544	
545		for _, route := range routes {
546			if !route.Valid {
547				continue
548			}
549			nonHTTPS := hasNonHTTPSAttachment(route.ParentRefs, listenerProtocols)
550			acceptedHostnames := collectAcceptedHostnames(route.ParentRefs)
551			if len(acceptedHostnames) == 0 {
552				continue
553			}
554			for i, rule := range route.Spec.Rules {
555				if !rule.ValidMatches || !rule.Filters.Valid {
556					continue
557				}
558				for j, f := range rule.Filters.Filters {
559					af := oidcAuthFilterFrom(f)
560					if af == nil {
561						continue
562					}
563					if nonHTTPS && af.Valid {
564						af.Conditions = append(af.Conditions,
565							conditions.NewAuthenticationFilterInvalid("OIDC authentication requires an HTTPS listener"),
566						)
567						af.Valid = false
568					}
569					filterRefs[af] = append(filterRefs[af], oidcRuleRef{route: route, ruleIdx: i, filterIdx: j})
570					if af.Valid {
571						nsname := types.NamespacedName{Namespace: af.Source.Namespace, Name: af.Source.Name}
572						for _, hostname := range acceptedHostnames {
573							if hostnameToFilters[hostname] == nil {
574								hostnameToFilters[hostname] = make(map[types.NamespacedName]*AuthenticationFilter)
575							}
576							hostnameToFilters[hostname][nsname] = af
577						}
578					}
579				}
580			}
581		}
582	
583		return hostnameToFilters, filterRefs
584	}
585	
586	// propagateInvalidOIDCFiltersToRouteRules marks route rules as having an invalid filter when their referenced
587	// OIDC filter was invalidated by URI conflict detection. This ensures the dataplane treats those rules as
588	// invalid rather than silently skipping authentication.
589	func propagateInvalidOIDCFiltersToRouteRules(filterRefs map[*AuthenticationFilter][]oidcRuleRef) {
590		const invalidMsg = "OIDC filter is invalid; see filter status for details"
591	
592		invalidatedRoutes := make(map[*L7Route]struct{})
593		for af, refs := range filterRefs {
594			if af.Valid {
595				continue
596			}
597			for _, ref := range refs {
598				ref.route.Spec.Rules[ref.ruleIdx].Filters.Filters[ref.filterIdx].ResolvedExtensionRef.Valid = false
599				ref.route.Spec.Rules[ref.ruleIdx].Filters.Valid = false
600				invalidatedRoutes[ref.route] = struct{}{}
601			}
602		}
603	
604		for route := range invalidatedRoutes {
605			mergeOrAppendRouteCondition(route, conditions.NewRouteResolvedRefsInvalidFilter(invalidMsg))
606		}
607	}
608	
609	// mergeOrAppendRouteCondition appends newCond to route.Conditions unless a condition with the same
610	// Type/Status/Reason already exists, in which case newCond's message is appended to it to avoid
611	// the last-wins deduplication in status preparation silently dropping earlier messages.
612	func mergeOrAppendRouteCondition(route *L7Route, newCond conditions.Condition) {
613		for i, existing := range route.Conditions {
614			if existing.Type == newCond.Type && existing.Status == newCond.Status && existing.Reason == newCond.Reason {
615				if !strings.Contains(existing.Message, newCond.Message) {
616					route.Conditions[i].Message = existing.Message + "; " + newCond.Message
617				}
618				return
619			}
620		}
621		route.Conditions = append(route.Conditions, newCond)
622	}
623	
624	// collectAcceptedHostnames returns a deduplicated list of all accepted hostnames across all parent refs.
625	func collectAcceptedHostnames(parentRefs []ParentRef) []v1.Hostname {
626		seen := make(map[v1.Hostname]struct{})
627		var hostnames []v1.Hostname
628		for _, ref := range parentRefs {
629			if ref.Attachment == nil {
630				continue
631			}
632			for _, hs := range ref.Attachment.AcceptedHostnames {
633				for _, h := range hs {
634					hostname := v1.Hostname(h)
635					if _, exists := seen[hostname]; !exists {
636						seen[hostname] = struct{}{}
637						hostnames = append(hostnames, hostname)
638					}
639				}
640			}
641		}
642		return hostnames
643	}
644	
645	// oidcAuthFilterFrom returns the AuthenticationFilter from a Filter if it is an OIDC extension ref, or nil.
646	func oidcAuthFilterFrom(f Filter) *AuthenticationFilter {
647		if f.FilterType != FilterExtensionRef ||
648			f.ResolvedExtensionRef == nil ||
649			f.ResolvedExtensionRef.AuthenticationFilter == nil {
650			return nil
651		}
652		af := f.ResolvedExtensionRef.AuthenticationFilter
653		if af.Source.Spec.Type != ngfAPI.AuthTypeOIDC {
654			return nil
655		}
656		return af
657	}
658	
659	// checkOIDCURIConflictsForHostname checks the given filters for duplicate logout, front-channel logout,
660	// and path-only redirect URIs on a single hostname, marking conflicting filters invalid.
661	func checkOIDCURIConflictsForHostname(
662		hostname v1.Hostname,
663		filtersMap map[types.NamespacedName]*AuthenticationFilter,
664	) {
665		type filterEntry struct {
666			filter *AuthenticationFilter
667			nsname types.NamespacedName
668		}
669	
670		entries := make([]filterEntry, 0, len(filtersMap))
671		for nsname, af := range filtersMap {
672			entries = append(entries, filterEntry{nsname: nsname, filter: af})
673		}
674		slices.SortFunc(entries, func(a, b filterEntry) int {
675			if ngfsort.LessObjectMeta(&a.filter.Source.ObjectMeta, &b.filter.Source.ObjectMeta) {
676				return -1
677			}
678			if ngfsort.LessObjectMeta(&b.filter.Source.ObjectMeta, &a.filter.Source.ObjectMeta) {
679				return 1
680			}
681			return 0
682		})
683	
684		// All three URI types share the same NGINX location path spaces,
685		// so we use a single map to catch both same-type and cross-type conflicts.
686		claimedPaths := make(map[string]oidcClaimedEntry)
687	
688		for _, entry := range entries {
689			if !entry.filter.Valid {
690				continue
691			}
692			oidc := entry.filter.Source.Spec.OIDC
693			if oidc.Logout != nil && oidc.Logout.URI != nil {
694				claimOIDCURI(entry.filter, entry.nsname, *oidc.Logout.URI, "logout URI", hostname, claimedPaths)
695			}
696			if entry.filter.Valid && oidc.Logout != nil && oidc.Logout.FrontChannelLogoutURI != nil {
697				claimOIDCURI(
698					entry.filter, entry.nsname,
699					*oidc.Logout.FrontChannelLogoutURI, "front-channel logout URI", hostname, claimedPaths,
700				)
701			}
702			if entry.filter.Valid && oidc.RedirectURI != nil && strings.HasPrefix(*oidc.RedirectURI, "/") {
703				claimOIDCURI(entry.filter, entry.nsname, *oidc.RedirectURI, "redirect URI", hostname, claimedPaths)
704			}
705		}
706	}
707	
708	// claimOIDCURI attempts to register uri for the given filter on a hostname. If another filter already claimed
709	// that URI on the same hostname, the current filter is marked invalid with a condition.
710	func claimOIDCURI(
711		af *AuthenticationFilter,
712		afNsname types.NamespacedName,
713		uri, uriType string,
714		hostname v1.Hostname,
715		claimed map[string]oidcClaimedEntry,
716	) {
717		if winner, exists := claimed[uri]; exists {
718			msg := fmt.Sprintf(
719				"%s %q conflicts with %s of OIDC filter %s/%s on hostname %q",
720				uriType, uri, winner.uriType, winner.owner.Namespace, winner.owner.Name, hostname,
721			)
722			cond := conditions.NewAuthenticationFilterInvalid(msg)
723			af.Conditions = append(af.Conditions, cond)
724			af.Valid = false
725		} else {
726			claimed[uri] = oidcClaimedEntry{owner: afNsname, uriType: uriType}
727		}
728	}
