131	// deduplicateIncludes deduplicates all the includes using the include name as the identifier.
132	// Duplicate includes are possible when a single policy targets multiple resources, or a snippets filter
133	// is referenced on multiple routing rules.
134	func deduplicateIncludes(includes []shared.Include) []shared.Include {
135		uniqueIncludes := make(map[string]shared.Include)
136		for _, i := range includes {
137			if _, ok := uniqueIncludes[i.Name]; !ok {
138				uniqueIncludes[i.Name] = i
139			}
140		}
141	
142		results := make([]shared.Include, 0, len(uniqueIncludes))
143		for _, i := range uniqueIncludes {
144			results = append(results, i)
