151	// A SnippetsFilter can have both a server snippet and a location snippet. This function converts
152	// all the location snippets in the SnippetsFilters to includes.
153	func createIncludesFromLocationSnippetsFilters(filters []dataplane.SnippetsFilter) []shared.Include {
154		if len(filters) == 0 {
